  { name: 'Capgemini', type: 'Service', package: '4-9 LPA', logo: '🔵', minCgpa: 6.5, minSkill: 5, minProjects: 1, minCerts: 1, noBacking: false, color: '#0070ad' },
  { name: 'Accenture', type: 'Service', package: '4-10 LPA', logo: '🟣', minCgpa: 6.5, minSkill: 5, minProjects: 1, minCerts: 0, noBacking: false, color: '#a100ff' },
  { name: 'Deloitte', type: 'Consulting', package: '6-16 LPA', logo: '⬛', minCgpa: 7.0, minSkill: 6, minProjects: 1, minCerts: 1, noBacking: false, color: '#86bc25' },
  { name: 'Paytm', type: 'Fintech', package: '10-25 LPA', logo: '🔵', minCgpa: 7.0, minSkill: 6, minProjects: 2, minCerts: 0, noBacking: false, color: '#00baf2' },
  { name: 'PhonePe', type: 'Fintech', package: '12-30 LPA', logo: '🟣', minCgpa: 7.5, minSkill: 7, minProjects: 2, minCerts: 1, noBacking: false, color: '#5f259f' },
  { name: 'HDFC Bank', type: 'Banking', package: '5-12 LPA', logo: '🏦', minCgpa: 6.5, minSkill: 4, minProjects: 0, minCerts: 0, noBacking: false, color: '#004c97' },
  { name: 'IBM', type: 'Service', package: '5-14 LPA', logo: '🔵', minCgpa: 7.0, minSkill: 5, minProjects: 1, minCerts: 1, noBacking: false, color: '#1f70c1' },
];

export default function CompanyMatch() {
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('All');
  const [selected, setSelected] = useState(null);

  useEffect(() => {
    API.get('/profile').then(res => {
      setProfile(res.data.profile);
      setLoading(false);
    }).catch(() => setLoading(false));
  }, []);

  const getMatchScore = (company) => {
    if (!profile) return 0;
    let score = 0;
    let total = 5;
    if ((profile.cgpa || 0) >= company.minCgpa) score++;
    if ((profile.programming_skill || 0) >= company.minSkill) score++;
    if ((profile.projects || 0) >= company.minProjects) score++;
    if ((profile.certifications || 0) >= company.minCerts) score++;
    if (!company.noBacking || (profile.backlogs || 0) === 0) score++;
    return Math.round((score / total) * 100);
  };

  const getMissingReqs = (company) => {
    if (!profile) return [];
    const missing = [];
    if ((profile.cgpa || 0) < company.minCgpa) missing.push(`CGPA ≥ ${company.minCgpa} (yours: ${profile.cgpa || 0})`);
    if ((profile.programming_skill || 0) < company.minSkill) missing.push(`Programming skill ≥ ${company.minSkill}/10 (yours: ${profile.programming_skill || 0})`);
    if ((profile.projects || 0) < company.minProjects) missing.push(`${company.minProjects} projects (yours: ${profile.projects || 0})`);
    if ((profile.certifications || 0) < company.minCerts) missing.push(`${company.minCerts} certifications (yours: ${profile.certifications || 0})`);
    if (company.noBacking && (profile.backlogs || 0) > 0) missing.push(`Clear all backlogs (you have ${profile.backlogs})`);
    return missing;
  };

  const getStatus = (score) => {
    if (score === 100) return { label: '✅ Eligible', color: '#10b981', bg: 'rgba(16,185,129,0.1)' };
    if (score >= 80) return { label: '🟡 Almost There', color: '#f59e0b', bg: 'rgba(245,158,11,0.1)' };
    if (score >= 60) return { label: '🔵 Working Towards', color: '#6366f1', bg: 'rgba(99,102,241,0.1)' };
    return { label: '🔴 Not Yet', color: '#ef4444', bg: 'rgba(239,68,68,0.08)' };
  };

  const types = ['All', 'Product', 'Service', 'Startup', 'Fintech', 'Consulting', 'Banking'];
  const filtered = COMPANIES.filter(c => filter === 'All' || c.type === filter)
    .map(c => ({ ...c, matchScore: getMatchScore(c) }))
    .sort((a, b) => b.matchScore - a.matchScore);

  const eligible = filtered.filter(c => c.matchScore === 100).length;

  if (loading) return (
    <div style={{ display:'flex', justifyContent:'center', alignItems:'center', height:300, flexDirection:'column', gap:16 }}>
      <div style={{ width:40, height:40, border:'3px solid var(--border)', borderTop:'3px solid var(--accent)', borderRadius:'50%', animation:'spin 0.8s linear infinite' }} />
      <p style={{ color:'var(--text2)' }}>Analyzing your profile...</p>
    </div>
  );

  if (!profile) return (
    <div className="content-area fade-in" style={{ maxWidth: 500, margin: '0 auto', textAlign: 'center', paddingTop: 60 }}>
      <div style={{ fontSize: 64, marginBottom: 16 }}>📋</div>
      <h2 style={{ fontFamily: 'Space Grotesk', marginBottom: 12 }}>Complete Your Profile First</h2>
      <p style={{ color: 'var(--text2)', marginBottom: 24 }}>We need your academic details and skills to match you with companies.</p>
      <a href="/profile" className="btn btn-primary">Go to Profile →</a>
    </div>
  );

  return (
    <div className="content-area fade-in">
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', marginBottom:20, flexWrap:'wrap', gap:12 }}>
        <div>
          <h1 className="section-title">📊 Company Match</h1>
          <p className="section-sub">Based on your profile — see exactly which companies you qualify for right now</p>
        </div>
        <div style={{ display:'flex', gap:12 }}>
          <div style={{ background:'var(--card)', border:'1px solid var(--border)', borderRadius:10, padding:'10px 18px', textAlign:'center' }}>
            <div style={{ fontSize:22, fontWeight:800, color:'#10b981' }}>{eligible}</div>
            <div style={{ fontSize:11, color:'var(--text3)' }}>Eligible Now</div>
          </div>
          <div style={{ background:'var(--card)', border:'1px solid var(--border)', borderRadius:10, padding:'10px 18px', textAlign:'center' }}>
            <div style={{ fontSize:22, fontWeight:800, color:'var(--accent)' }}>{COMPANIES.length}</div>
            <div style={{ fontSize:11, color:'var(--text3)' }}>Total Companies</div>
          </div>
        </div>
      </div>

      {/* Filters */}
      <div className="card" style={{ marginBottom:20, padding:'12px 16px' }}>
        <div style={{ display:'flex', gap:8, flexWrap:'wrap' }}>
          {types.map(t => (
            <button key={t} onClick={() => setFilter(t)}
              style={{ padding:'6px 14px', borderRadius:20, fontSize:12, fontWeight:600, cursor:'pointer', border:'none', background:filter===t?'var(--accent)':'var(--bg2)', color:filter===t?'white':'var(--text2)', fontFamily:'Outfit,sans-serif' }}>
              {t}
            </button>
          ))}
        </div>
      </div>

      {/* Company grid */}
      <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fill, minmax(280px, 1fr))', gap:14 }}>
        {filtered.map(company => {
          const status = getStatus(company.matchScore);
          const missing = getMissingReqs(company);
          return (
            <div key={company.name} onClick={() => setSelected(selected?.name === company.name ? null : company)}
              className="card"
              style={{ cursor:'pointer', borderLeft:`3px solid ${status.color}`, transition:'all 0.2s', background: selected?.name === company.name ? `${status.color}10` : 'var(--card)' }}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', marginBottom:10 }}>
                <div>
                  <div style={{ fontSize:16, fontWeight:700 }}>{company.logo} {company.name}</div>
                  <div style={{ fontSize:11, color:'var(--text3)', marginTop:2 }}>{company.type} • {company.package}</div>
                </div>
                <div style={{ textAlign:'center' }}>
                  <div style={{ fontSize:20, fontWeight:800, color:status.color }}>{company.matchScore}%</div>
                  <div style={{ fontSize:9, color:'var(--text3)' }}>match</div>
                </div>
              </div>

              {/* Match bar */}
              <div style={{ height:6, background:'var(--bg2)', borderRadius:10, marginBottom:8 }}>
                <div style={{ height:'100%', borderRadius:10, background:status.color, width:`${company.matchScore}%`, transition:'width 0.5s' }} />
              </div>

              <span style={{ fontSize:11, fontWeight:700, color:status.color, background:status.bg, padding:'3px 10px', borderRadius:20 }}>{status.label}</span>

              {/* Expanded details */}
              {selected?.name === company.name && (
                <div style={{ marginTop:14, paddingTop:14, borderTop:'1px solid var(--border)' }}>
                  {missing.length === 0 ? (
                    <div style={{ fontSize:13, color:'#10b981', fontWeight:600 }}>🎉 You meet all requirements! Apply now.</div>
                  ) : (
                    <div>
                      <div style={{ fontSize:12, fontWeight:700, color:'var(--text2)', marginBottom:8 }}>📋 What you need to improve:</div>
                      {missing.map((m, i) => (
                        <div key={i} style={{ fontSize:12, color:'#ef4444', marginBottom:4, display:'flex', gap:6, alignItems:'flex-start' }}>
                          <span>•</span><span>{m}</span>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}
